from typing import List, Dict, Any, Optional, Callable
from leann.api import SearchResult
from leann.metadata_filter import MetadataFilterEngine
from collections import defaultdict


def apply_dynamic_filters(
    search_results: List[SearchResult],
    filter_specs: Dict[str, Dict[str, Any]],
    filter_logic: str = "AND"
) -> List[SearchResult]:
    """Apply dynamic metadata filters to search results with configurable logic.

    Args:
        search_results: List of SearchResult objects to filter
        filter_specs: Dictionary of filter specifications.
            Format: {"field_name": {"operator": value}}
            Example: {"category": {"==": "tech"}, "rating": {">=": 4.0}}
        filter_logic: "AND" (all filters must match) or "OR" (any filter matches)

    Returns:
        Filtered list of SearchResult objects
    """
    if not filter_specs:
        return search_results

    filter_logic = filter_logic.upper()
    engine = MetadataFilterEngine()

    # Convert SearchResult objects to dictionaries for filtering
    result_dicts = []
    for result in search_results:
        result_dicts.append({
            "id": result.id,
            "score": result.score,
            "text": result.text,
            "metadata": result.metadata
        })

    if filter_logic == "AND":
        # Apply AND logic: all filters must pass
        filtered_dicts = engine.apply_filters(result_dicts, filter_specs)
    elif filter_logic == "OR":
        # Apply OR logic: at least one filter must pass
        passed_results = set()

        # Check each filter condition individually
        for field_name, condition in filter_specs.items():
            single_filter = {field_name: condition}
            filtered_dicts = engine.apply_filters(result_dicts, single_filter)

            # Add IDs of results that pass this individual filter
            for result_dict in filtered_dicts:
                passed_results.add(result_dict["id"])

        # Reconstruct filtered results maintaining original order and structure
        filtered_dicts = []
        id_to_dict = {d["id"]: d for d in result_dicts}
        for result_id in passed_results:
            if result_id in id_to_dict:
                filtered_dicts.append(id_to_dict[result_id])
    else:
        raise ValueError(f"Unsupported filter logic: {filter_logic}. Use 'AND' or 'OR'.")

    # Convert filtered dictionaries back to SearchResult objects
    filtered_results = []
    for result_dict in filtered_dicts:
        filtered_results.append(
            SearchResult(
                id=result_dict["id"],
                score=result_dict["score"],
                text=result_dict["text"],
                metadata=result_dict["metadata"]
            )
        )

    return filtered_results

